const https = require("https");
const http  = require("http");
const fs    = require("fs");
const path  = require("path");
const url   = require("url");

const PORT         = process.env.PORT || 3000;
const IDEOGRAM_KEY = process.env.IDEOGRAM_API_KEY || "";
const IMG_B64      = "";

function buildPrompt(ev) {
  var name    = (ev.name    || "").trim();
  var prefix  = (ev.prefix  || "").trim();
  var genre   = (ev.genre   || "").trim();
  var day     = (ev.day     || "").trim();
  var date    = (ev.date    || "").trim();
  var dj      = (ev.dj      || "").trim();
  var contact = (ev.contact || "").trim();
  var time    = (ev.time    || "").trim();
  var entry   = (ev.entry   || "").trim();

  var djList = dj.length ? dj.split(",").map(function(d){return d.trim();}).filter(Boolean) : [];

  var newTexts = [];
  if (prefix)       newTexts.push("Small text above title: \"" + prefix + "\"");
  else              newTexts.push("Remove any small text above the main title");
  if (name)         newTexts.push("Main title: \"" + name + "\"");
  if (genre)        newTexts.push("Banner/edition text: \"" + genre + "\"");
  if (day)          newTexts.push("Day: \"" + day.toUpperCase() + "\"");
  if (date)         newTexts.push("Date: \"" + date + "\"");
  if (djList.length) newTexts.push("Acts/DJs (replace all existing): " + djList.map(function(d){return "\""+d+"\"";}).join(", "));
  else               newTexts.push("Remove all DJ and act names");
  if (contact)      newTexts.push("Website: \"" + contact + "\"");
  if (time)         newTexts.push("\"Einlass: " + time + " Uhr\"");
  if (entry)        newTexts.push("\"Eintritt: " + entry + "\"");

  return "Edit this nightclub event flyer. Keep ALL visual elements exactly the same — people, backgrounds, effects, colors, decorations, fonts styles. " +
    "Only replace the text with these new values:\n" +
    newTexts.map(function(t,i){return (i+1)+". "+t;}).join("\n") +
    "\nAny text not listed above must be removed. Do not add any text not listed.";
}

var server = http.createServer(function(req, res) {
  var p = url.parse(req.url).pathname;
  res.setHeader("Access-Control-Allow-Origin","*");
  res.setHeader("Access-Control-Allow-Headers","Content-Type");
  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && p === "/") {
    fs.readFile(path.join(__dirname,"public","index.html"), function(err, data) {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type","text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && p === "/api/generate") {
    if (!IDEOGRAM_KEY) {
      res.writeHead(500);
      res.end(JSON.stringify({error:"IDEOGRAM_API_KEY not configured"}));
      return;
    }

    var body = "";
    req.on("data", function(c){ body += c; });
    req.on("end", function() {
      var ev;
      try { ev = JSON.parse(body); } catch(e) {
        res.writeHead(400); res.end(JSON.stringify({error:"Invalid JSON"})); return;
      }

      var prompt = buildPrompt(ev);
      console.log("Prompt:", prompt);

      var imgBuffer = Buffer.from(IMG_B64, "base64");
      var boundary = "----NKBoundary" + Date.now().toString(36);
      var CRLF = "\r\n";

      // image_request as JSON part
      // Ideogram v3 remix: each field is a separate form part
      function formField(name, value) {
        return Buffer.from(
          "--"+boundary+CRLF+
          "Content-Disposition: form-data; name=\""+name+"\""+CRLF+CRLF+
          value+CRLF, "utf8"
        );
      }

      var imgPart = Buffer.concat([
        Buffer.from(
          "--"+boundary+CRLF+
          "Content-Disposition: form-data; name=\"image\"; filename=\"template.jpg\""+CRLF+
          "Content-Type: image/jpeg"+CRLF+CRLF, "utf8"
        ),
        imgBuffer,
        Buffer.from(CRLF, "utf8")
      ]);

      var reqBody = Buffer.concat([
        formField("prompt", prompt),
        formField("aspect_ratio", "9:16"),
        formField("rendering_speed", "QUALITY"),
        formField("magic_prompt", "OFF"),
        formField("style_type", "REALISTIC"),
        formField("image_weight", "70"),
        imgPart,
        Buffer.from("--"+boundary+"--"+CRLF, "utf8")
      ]);

      console.log("Calling Ideogram v3 remix, body size:", reqBody.length);

      var apiReq = https.request({
        hostname: "api.ideogram.ai",
        path: "/v1/ideogram-v3/remix",
        method: "POST",
        headers: {
          "Api-Key": IDEOGRAM_KEY,
          "Content-Type": "multipart/form-data; boundary="+boundary,
          "Content-Length": reqBody.length
        }
      }, function(apiRes) {
        var data = "";
        apiRes.on("data", function(c){ data += c; });
        apiRes.on("end", function() {
          console.log("Ideogram status:", apiRes.statusCode, data.substring(0,400));
          try {
            var j = JSON.parse(data);
            if (apiRes.statusCode !== 200) {
              return res.writeHead(apiRes.statusCode),
                     res.end(JSON.stringify({error: j.detail || j.message || data.substring(0,300)}));
            }
            var imgUrl = j.data && j.data[0] && j.data[0].url;
            if (!imgUrl) return res.writeHead(500), res.end(JSON.stringify({error:"No image URL: "+data.substring(0,200)}));
            res.setHeader("Content-Type","application/json");
            res.writeHead(200);
            res.end(JSON.stringify({url: imgUrl}));
          } catch(e) {
            res.writeHead(500); res.end(JSON.stringify({error:"Parse error: "+data.substring(0,200)}));
          }
        });
      });
      apiReq.on("error", function(e){ res.writeHead(500); res.end(JSON.stringify({error:e.message})); });
      apiReq.write(reqBody);
      apiReq.end();
    });
    return;
  }

  res.writeHead(404); res.end("Not found");
});

server.timeout = 120000;
server.listen(PORT, function(){ console.log("NightKit Ideogram v3 on port "+PORT); });
